/*
 * Lookup for tables:
 *     decomp_table_offset and decomp_table_index.
 */
static uint16
normalization_index(char32_t cp)
{
	uint16		offset_idx,
				offset;

	offset_idx = cp >> 6;

	if (offset_idx > 3049)
		return 0;

	offset = decomp_table_offset[offset_idx];

	return decomp_table_index[offset + (cp & 63)];
}

/*
 * Lookup for tables:
 *     inverse_table_offset and inverse_table_index.
 */
static uint16
inverse_index(char32_t cp)
{
	uint16		offset_idx,
				offset;

	offset_idx = cp >> 6;

	if (offset_idx > 1462)
		return 0;

	offset = inverse_table_offset[offset_idx];

	return inverse_table_index[offset + (cp & 63)];
}

/*
 * normalization_inverse()
 *
 * Returns the code point for recomposition of the reordered Unicode string
 * based on two code points.
 * Codepoint 0x0000 means "not found".
 */
static char32_t
normalization_inverse(char32_t first, char32_t second)
{
	uint16		idx;
	uint32		start,
				stop;
	const uint16 *entry;

	idx = inverse_index(first);
	entry = &UnicodeDecompInverseSecond[idx];

	start = entry[0] << 16 | entry[1];
	stop = start + entry[2];

	if (idx != 0 && second >= start && second <= stop)
	{
		return UnicodeDecompInverseCodes[entry[second - start + 3]];
	}

	return 0x0000;
}
